const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
if (body.skip) return { json: { _skipped: true, reason: 'skip flag set by caller' } };
const secret = body.internal_secret || '';
if (!secret || secret !== (process.env.INTERNAL_EMAIL_SECRET || '')) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.policy_review_id) return { json: { _empty: true, error: 'policy_review_id required' } };
return { json: { _authorized: true, policy_review_id: body.policy_review_id } };

const review = $('Fetch Review').first().json;
const r = Array.isArray(review) ? review[0] : review;
if (!r || !r.id) return { json: { _not_found: true, error: 'review not found' } };
const tplRows = $input.item.json;
const tpl = (Array.isArray(tplRows) ? tplRows[0] : tplRows) || null;
// Fallback to annual_review_due template if no exact match.
if (!tpl) return { json: { _no_template: true, review: r, error: 'no template — using generic intent' } };
return { json: { review: r, template: tpl } };

const carry = $('Carry Both').item.json;
const leadRows = $input.item.json;
const lead = (Array.isArray(leadRows) ? leadRows[0] : leadRows) || {};
const tpl = carry.template;
const review = carry.review;
const firstName = lead.first_name || (lead.full_name || '').split(' ')[0] || 'there';
const company = lead.company || 'your business';
const systemPrompt = [
  'You personalize a video script template for the INSURANCE vertical (vertical_id=insurance).',
  'Trigger event: ' + tpl.trigger_event,
  'Tone: ' + tpl.tone,
  'Persona: ' + tpl.recommended_persona_id + '/' + tpl.recommended_look_id,
  'Duration target: ' + tpl.duration_seconds + ' seconds',
  '',
  'Replace template {{variables}} with concrete personalized details from client context.',
  'Available context: first_name=' + firstName + ', company=' + company + ', advisor_company=Crystallux Insurance, signal_type=' + (review.trigger_signal_type || tpl.trigger_event) + ', review_type=' + review.review_type,
  '',
  'Output PLAIN TEXT only — the final spoken script. No markdown. No preamble. Match the duration target (~150 words for 60s).'
].join('\n');
return { json: {
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 600,
    temperature: 0.6,
    system: systemPrompt,
    messages: [ { role: 'user', content: 'Template:\n' + tpl.script_template + '\n\nGenerate the personalized script now. Plain text only.' } ]
  },
  review_id: review.id,
  client_id: review.client_id,
  lead_id: review.lead_id
} };
